from flask import Flask, request, jsonify, session, redirect, url_for
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import secrets
import time

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

users = {
    "alice": {
        "password_hash": generate_password_hash("password123"),
        "mfa_enabled": True,
        "otp_secret": pyotp.random_base32(),
        "roles": ["web"]
    },
    "bob": {
        "password_hash": generate_password_hash("password456"),
        "mfa_enabled": False,
        "otp_secret": None,
        "roles": ["web", "api"]
    },
    "service_account": {
        "password_hash": generate_password_hash("servicepass"),
        "mfa_enabled": True,
        "otp_secret": pyotp.random_base32(),
        "roles": ["api"]
    }
}

api_tokens = {}

def issue_api_token(username):
    token = secrets.token_urlsafe(32)
    api_tokens[token] = {
        "username": username,
        "issued_at": int(time.time())
    }
    return token

def authenticate_user(username, password):
    user = users.get(username)
    if not user:
        return None
    if not check_password_hash(user["password_hash"], password):
        return None
    return user

def login_user_session(username):
    session.clear()
    session["authenticated"] = True
    session["username"] = username
    session["mfa_complete"] = True

def login_pending_mfa(username):
    session.clear()
    session["authenticated"] = False
    session["username_pending_mfa"] = username
    session["mfa_complete"] = False

def current_user():
    if session.get("authenticated") and session.get("mfa_complete"):
        username = session.get("username")
        return username, users.get(username)
    return None, None

@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or request.form
    username = data.get("username")
    password = data.get("password")

    if not username or not password:
        return jsonify({"error": "username and password are required"}), 400

    user = authenticate_user(username, password)
    if not user:
        return jsonify({"error": "invalid credentials"}), 401

    if user.get("mfa_enabled"):
        login_pending_mfa(username)
        return jsonify({
            "message": "MFA required",
            "mfa_required": True,
            "next": "/verify-otp"
        }), 200

    login_user_session(username)
    return jsonify({
        "message": "Login successful",
        "mfa_required": False,
        "username": username
    }), 200

@app.route("/verify-otp", methods=["POST"])
def verify_otp():
    data = request.get_json(silent=True) or request.form
    otp = data.get("otp")
    username = session.get("username_pending_mfa")

    if not username:
        return jsonify({"error": "no pending MFA challenge"}), 400

    user = users.get(username)
    if not user or not user.get("mfa_enabled") or not user.get("otp_secret"):
        return jsonify({"error": "invalid MFA state"}), 400

    if not otp:
        return jsonify({"error": "otp is required"}), 400

    totp = pyotp.TOTP(user["otp_secret"])
    if not totp.verify(str(otp), valid_window=1):
        return jsonify({"error": "invalid otp"}), 401

    session.clear()
    session["authenticated"] = True
    session["username"] = username
    session["mfa_complete"] = True

    return jsonify({
        "message": "MFA verification successful",
        "username": username
    }), 200

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = data.get("username")
    password = data.get("password")

    if not username or not password:
        return jsonify({"error": "username and password are required"}), 400

    user = authenticate_user(username, password)
    if not user:
        return jsonify({"error": "invalid credentials"}), 401

    token = issue_api_token(username)
    return jsonify({
        "message": "Direct API login successful",
        "username": username,
        "token": token,
        "mfa_skipped": True
    }), 200

@app.route("/protected", methods=["GET"])
def protected():
    username, user = current_user()
    if not user:
        return jsonify({"error": "authentication required"}), 401

    return jsonify({
        "message": "Access granted",
        "username": username
    }), 200

@app.route("/api/protected", methods=["GET"])
def api_protected():
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"error": "missing bearer token"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    token_data = api_tokens.get(token)
    if not token_data:
        return jsonify({"error": "invalid token"}), 401

    return jsonify({
        "message": "API access granted",
        "username": token_data["username"]
    }), 200

@app.route("/logout", methods=["POST"])
def logout():
    session.clear()
    return jsonify({"message": "logged out"}), 200

@app.route("/mfa-secret/<username>", methods=["GET"])
def get_mfa_secret(username):
    user = users.get(username)
    if not user:
        return jsonify({"error": "user not found"}), 404
    if not user.get("mfa_enabled"):
        return jsonify({"error": "mfa not enabled for user"}), 400
    return jsonify({
        "username": username,
        "otp_secret": user["otp_secret"]
    }), 200

